import datetime as _dt
import requests
import pandas


__all__ = [
    "get_counts",
    "get_recent_changes",
    "get_recent_changes_ids",
    "get_recent_changes_names",
]


def get_counts():
    """Get Counts for WikiPathways Stats

    Retrieve information about various total counts at WikiPathways.

    Returns:
        pandas.DataFrame or None: A dataframe of counts including pathways, authors,
            organisms, and other WikiPathways statistics.
            Returns None if no results or on error.

    Examples:
        >>> get_counts()
    """
    try:
        response = requests.get('https://www.wikipathways.org/json/getCounts.json')
        response.raise_for_status()
        data = response.json()

        df = pandas.DataFrame([data])

        return df

    except requests.exceptions.RequestException as e:
        print(f"Error fetching data: {e}")
        return None
    except Exception as e:
        print(f"Error processing data: {e}")
        return None


_INFO_URL = "https://www.wikipathways.org/json/getPathwayInfo.json"
_DROP_FIELDS = {"authors", "description", "citedIn"}


def _normalize_timestamp(timestamp):
    """Return the cutoff date derived from the provided timestamp."""
    if timestamp is None:
        timestamp = 20070301
    text = str(timestamp)[:8]
    if len(text) != 8:
        raise ValueError("Timestamp must contain at least 8 digits (YYYYMMDD).")
    try:
        return _dt.datetime.strptime(text, "%Y%m%d").date()
    except ValueError as exc:
        raise ValueError("Timestamp must be in YYYYMMDD format.") from exc


def _parse_revision_date(raw):
    """Convert revision text to a date if possible."""
    if not raw:
        return None
    raw = raw.strip()
    if not raw:
        return None

    iso_candidate = raw[:10]
    try:
        return _dt.date.fromisoformat(iso_candidate)
    except ValueError:
        pass

    basic_candidate = raw[:8]
    try:
        return _dt.datetime.strptime(basic_candidate, "%Y%m%d").date()
    except ValueError:
        return None


def _fetch_recent_changes_json():
    """Fetch the recent changes JSON payload."""
    try:
        response = requests.get(_INFO_URL, timeout=30)
        response.raise_for_status()
        return response.json()
    except requests.HTTPError as exc:
        raise RuntimeError(
            f"Failed to retrieve JSON data ({exc.response.status_code})."
        ) from exc
    except requests.RequestException as exc:
        raise RuntimeError("Failed to retrieve JSON data (network error).") from exc


def get_recent_changes(timestamp=None):
    """Return recently changed pathways filtered by timestamp.

    Args:
        timestamp (str or int, optional): 8-digit cutoff (YYYYMMDD). Pathways with
            revision dates after this value are returned. Defaults to 20070301
            when omitted.

    Returns:
        pandas.DataFrame: Table of pathway records excluding authors, description,
            and citedIn fields.
    """
    cutoff = _normalize_timestamp(timestamp)
    payload = _fetch_recent_changes_json()
    entries = payload.get("pathwayInfo", [])

    template_columns = None
    records = []
    for entry in entries:
        if not isinstance(entry, dict):
            continue
        revision_date = _parse_revision_date(entry.get("revision"))
        if revision_date is None or revision_date <= cutoff:
            continue
        filtered = {k: v for k, v in entry.items() if k not in _DROP_FIELDS}
        if template_columns is None:
            template_columns = list(filtered.keys())
        records.append(filtered)

    if template_columns is None:
        template_columns = []
        for entry in entries:
            if not isinstance(entry, dict):
                continue
            for key in entry.keys():
                if key in _DROP_FIELDS or key in template_columns:
                    continue
                template_columns.append(key)

    frame = pandas.DataFrame.from_records(records, columns=template_columns)
    return frame


def get_recent_changes_ids(timestamp):
    """Get WPIDs of Recently Changed Pathways.

    Args:
        timestamp (str or int): 8-digit cutoff (YYYYMMDD).

    Returns:
        list: A list of pathway WPIDs.
    """
    return get_recent_changes(timestamp)['id'].tolist()


def get_recent_changes_names(timestamp):
    """Get Names of Recently Changed Pathways.

    Args:
        timestamp (str or int): 8-digit cutoff (YYYYMMDD).

    Returns:
        list: A list of pathway names.
    """
    return get_recent_changes(timestamp)['name'].tolist()

